import{o as n,b as s,d as a,e as t,E as e,G as o,x as p,u as i,h as c,H as r}from"./vendor.fbceabe1.js";import{i as l,_ as u}from"./Post.vue_vue&type=script&setup=true&lang.cc0cfda0.js";import"./app.60d80988.js";const h={xmlns:"http://www.w3.org/2000/svg","xmlns:xlink":"http://www.w3.org/1999/xlink",width:"1.2em",height:"1.2em",preserveAspectRatio:"xMidYMid meet",viewBox:"0 0 24 24",style:{"vertical-align":"middle",transform:"translateY(-5%)"}},k=a("path",{d:"M10 7a7 7 0 0 0 12 4.9v.1c0 5.523-4.477 10-10 10S2 17.523 2 12S6.477 2 12 2h.1A6.979 6.979 0 0 0 10 7zm-6 5a8 8 0 0 0 15.062 3.762A9 9 0 0 1 8.238 4.938A7.999 7.999 0 0 0 4 12z",fill:"currentColor"},null,-1);var d={render:function(a,t){return n(),s("svg",h,[k])}};const m={xmlns:"http://www.w3.org/2000/svg","xmlns:xlink":"http://www.w3.org/1999/xlink",width:"1.2em",height:"1.2em",preserveAspectRatio:"xMidYMid meet",viewBox:"0 0 24 24",style:{"vertical-align":"middle",transform:"translateY(-5%)"}},g=a("path",{d:"M12 18a6 6 0 1 1 0-12a6 6 0 0 1 0 12zm0-2a4 4 0 1 0 0-8a4 4 0 0 0 0 8zM11 1h2v3h-2V1zm0 19h2v3h-2v-3zM3.515 4.929l1.414-1.414L7.05 5.636L5.636 7.05L3.515 4.93zM16.95 18.364l1.414-1.414l2.121 2.121l-1.414 1.414l-2.121-2.121zm2.121-14.85l1.414 1.415l-2.121 2.121l-1.414-1.414l2.121-2.121zM5.636 16.95l1.414 1.414l-2.121 2.121l-1.414-1.414l2.121-2.121zM23 11v2h-3v-2h3zM4 11v2H1v-2h3z",fill:"currentColor"},null,-1);var f={render:function(a,t){return n(),s("svg",m,[g])}},y=t({expose:[],setup(t){function i(){l.value=!l.value}return(t,c)=>{const r=d,u=f;return n(),s("a",{class:"select-none",title:"Toggle Color Scheme",onClick:i},[e(a(r,null,null,512),[[o,p(l)]]),e(a(u,null,null,512),[[o,!p(l)]])])}}});const w={class:"prose m-auto"},b=r('<p>The page you are looking at is now powered by <a href="https://github.com/vitejs/vite">Vite</a>. This is something I want to do for a long while since Vite came out, and it’s finally done. As I have mentioned in my <a href="/posts/new-house">first blog post</a>, it was powered <a href="https://gridsome.org/">Gridsome</a> using Vue 2. With this overhaul, I can now take full advantage of Vue 3 and the <a href="https://v3.vuejs.org/guide/composition-api-introduction.html">Composition API</a> with the new <a href="https://github.com/vuejs/rfcs/pull/227"><code>&lt;script setup&gt;</code> SFC style</a>.</p><p>The reason for it taking me so long to do this is because I am busy (enjoy) doing <a href="https://americanexpress.io/yak-shaving">yak shaving</a>, for the tools I need to build this site.</p><h3 id="fundamentals"><a class="header-anchor" href="#fundamentals" aria-hidden="true">#</a> Fundamentals</h3><p>It begins with me trying to improve the DX using icons in <a href="/posts/journey-with-icons">this post</a>. At that time, Vue 3 just into RC, and Vite didn’t reach 1.0 yet. Hearing a lot of how good Vue 3 and Vite are, I decided to give them a try on building the icon site I need. Since Vite is so brand new thing, there aren’t really many tools/plugins out there, the ecosystem is way far from what Webpack has. So I took that as a chance for me to dive deep into how Vite works and do some contributions to its ecosystem, I made a few tools while making <a href="https://github.com/antfu/icones">Icônes</a>:</p><ul><li><a href="https://github.com/antfu/vite-plugin-components">vite-plugin-components</a> - On-demand components auto importing for Vite.</li><li><a href="https://github.com/antfu/vite-plugin-pwa">vite-plugin-pwa</a> - Zero-config PWA for Vite.</li><li><a href="https://github.com/antfu/purge-icons">vite-plugin-purge-icons</a> - Bundles icons on demand, with a Vite plugin.</li></ul><p>And found some awesome tools form the community:</p><ul><li><a href="https://github.com/iconify/iconify">Iconify</a> - Universal icon framework, by <a href="https://github.com/cyberalien">@cyberalien</a>.</li><li><a href="https://github.com/brattonross/vite-plugin-voie">vite-plugin-voie</a> - File system based routing for Vite, by <a href="https://github.com/brattonross">@brattonross</a>.</li><li><a href="https://github.com/hannoeru/vite-plugin-pages">vite-plugin-pages</a> - Another file system based route generator, by <a href="https://github.com/hannoeru">@hannoeru</a>.</li></ul><p>With them, I got the fundamentals of a Vite project setup that has file-based routing and component auto importing. Where I am quite satisfied with this as I can now focus more on the content and logic rather than getting distracted by the routes setup and component registering.</p><p>I also learned <a href="https://tailwindcss.com/">Tailwind CSS</a> as a replacement of the missing UI component libraries for Vue 3. It turns out that I really enjoy Tailwind’s way of rapid prototyping. As I got more control over styling things, it makes me think more about the design rather than just applying the default theme of the components library I use.</p><h3 id="dark-mode"><a class="header-anchor" href="#dark-mode" aria-hidden="true">#</a> Dark Mode</h3><p>Dark mode is support as an experimental feature in Tailwind CSS v1.8 and shipped in v2.0. It supports two modes for you to choose from - <code>media</code> and <code>class</code>. <code>media</code> is something that works out-of-box, based on users’ system preference. The limitation is that you can’t toggle it manually which is something I preferred to have. So go with <code>class</code> mode where I have more control over when to enable the dark theme. That says I would need to implement the toggling logic myself.</p><p>With the power of Vue’s Composition API, I am able to combine the best parts - reactive to the system’s preference while being able to override manually.</p><pre class="language-ts"><code class="language-ts"><span class="token keyword">import</span> <span class="token punctuation">{</span> useStorage<span class="token punctuation">,</span> usePreferredDark <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vueuse/core&#39;</span>\n\n<span class="token keyword">const</span> preferredDark <span class="token operator">=</span> <span class="token function">usePreferredDark</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token keyword">const</span> colorSchema <span class="token operator">=</span> <span class="token function">useStorage</span><span class="token punctuation">(</span><span class="token string">&#39;color-schema&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;auto&#39;</span><span class="token punctuation">)</span>\n\n<span class="token keyword">export</span> <span class="token keyword">const</span> isDark <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  <span class="token keyword">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> colorSchema<span class="token punctuation">.</span>value <span class="token operator">===</span> <span class="token string">&#39;auto&#39;</span>\n      <span class="token operator">?</span> preferredDark<span class="token punctuation">.</span>value\n      <span class="token operator">:</span> colorSchema<span class="token punctuation">.</span>value <span class="token operator">===</span> <span class="token string">&#39;dark&#39;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token keyword">set</span><span class="token punctuation">(</span>v<span class="token operator">:</span> <span class="token builtin">boolean</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">if</span> <span class="token punctuation">(</span>v <span class="token operator">===</span> preferredDark<span class="token punctuation">.</span>value<span class="token punctuation">)</span>\n      colorSchema<span class="token punctuation">.</span>value <span class="token operator">=</span> <span class="token string">&#39;auto&#39;</span>\n    <span class="token keyword">else</span>\n      colorSchema<span class="token punctuation">.</span>value <span class="token operator">=</span> v <span class="token operator">?</span> <span class="token string">&#39;dark&#39;</span> <span class="token operator">:</span> <span class="token string">&#39;light&#39;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n\n<span class="token function">watch</span><span class="token punctuation">(</span>\n  isDark<span class="token punctuation">,</span>\n  v <span class="token operator">=&gt;</span> document<span class="token punctuation">.</span>documentElement<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">toggle</span><span class="token punctuation">(</span><span class="token string">&#39;dark&#39;</span><span class="token punctuation">,</span> v<span class="token punctuation">)</span><span class="token punctuation">,</span>\n  <span class="token punctuation">{</span> immediate<span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>\n<span class="token punctuation">)</span>\n</code></pre><p>Try click it 👇🏼</p>',14),v=r('<p>If you would like to use it, I also extract the logic above into <a href="https://vueuse.js.org/core/usedark/"><code>useDark()</code> in VueUse</a>. Where you can simply do this</p><pre class="language-ts"><code class="language-ts"><span class="token keyword">import</span> <span class="token punctuation">{</span> useDark<span class="token punctuation">,</span> useToggle <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vueuse/core&#39;</span>\n\n<span class="token keyword">const</span> isDark <span class="token operator">=</span> <span class="token function">useDark</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token keyword">const</span> toggleDark <span class="token operator">=</span> <span class="token function">useToggle</span><span class="token punctuation">(</span>isDark<span class="token punctuation">)</span>\n</code></pre><h3 id="markdown"><a class="header-anchor" href="#markdown" aria-hidden="true">#</a> Markdown</h3><p>After making Icônes, I started working on the <a href="http://codecember.ink/">Codecember</a> project with <a href="https://blog.matsu.io/about">@octref</a>, an initiative of learning and creating generative arts in December. With the spirit of dogfooding, we have chosen Vite for building the site. In Codecember we would need to do have a prompt every day with some texts, code snippets, and demos. This comes with the problem that Vite does not have a plugin for handling markdown files at that moment, so I made one myself.</p><ul><li><a href="https://github.com/antfu/vite-plugin-md">vite-plugin-md</a> - Markdown for Vite.</li></ul><p>Basically, it uses <a href="https://markdown-it.github.io/"><code>markdown-it</code></a> to transform markdown into HTML and feed it into Vue’s template compiler. As the template is handled by Vue, we can easily support Vue components inside Markdown.</p><h3 id="syntax-highlighting"><a class="header-anchor" href="#syntax-highlighting" aria-hidden="true">#</a> Syntax Highlighting</h3><p>To get syntax highlight works in dark mode isn’t an easy task as well. <a href="https://github.com/shikijs/shiki">Shiki</a> inlined all the colors into the HTML so you would not be bored by the CSS namespace pollution, but that also means it will be really hard to get the colors aware of your global color scheme. <a href="https://prismjs.com/">Prism</a> on the other hand, uses the classes combining the CSS theme to do the job. It’s easier to merge two color schemes and make them aware of the <code>dark</code> trigger. The bad thing is, themes are often wrote by different authors with different styles of coloring and styling things. Sometimes, even the font and spacing could be different across different themes. If you ever ran into a similar situation, you should know what I mean. If you don’t (lucky you!), see <a href="https://github.com/PrismJS/prism-themes/tree/master/themes">Prism’s themes collection</a>(<a href="https://github.com/PrismJS/prism-themes/blob/c24ddffde2737293d9b2df7dc59939d527648863/themes/prism-vs.css#L9"><code>prism-vs.css</code></a> and <a href="https://github.com/PrismJS/prism-themes/blob/c24ddffde2737293d9b2df7dc59939d527648863/themes/prism-vsc-dark-plus.css#L6"><code>prism-vsc-dark-plus.css</code></a> for example).</p><p>Fight with them for a while you might be able to ease the misalignment eventually. But what if we can have a smarter way to do this?</p><ul><li><a href="https://github.com/antfu/prism-theme-vars">prism-theme-vars</a> - A customizable Prism.js theme using CSS variables.</li></ul><p>Instead of dealing with the lengthy CSS theme, now you can have one in less than 20 lines of CSS variables. For example:</p><pre class="language-css"><code class="language-css"><span class="token atrule"><span class="token rule">@import</span> <span class="token string">&quot;prism-theme-vars/base.css&quot;</span><span class="token punctuation">;</span></span>\n\n<span class="token selector">:root</span> <span class="token punctuation">{</span>\n  <span class="token property">--prism-foreground</span><span class="token punctuation">:</span> #393a34<span class="token punctuation">;</span>\n  <span class="token property">--prism-background</span><span class="token punctuation">:</span> #fbfbfb<span class="token punctuation">;</span>\n  <span class="token property">--prism-comment</span><span class="token punctuation">:</span> #b8c4b8<span class="token punctuation">;</span>\n  <span class="token property">--prism-string</span><span class="token punctuation">:</span> #c67b5d<span class="token punctuation">;</span>\n  <span class="token property">--prism-literal</span><span class="token punctuation">:</span> #3a9c9b<span class="token punctuation">;</span>\n  <span class="token property">--prism-keyword</span><span class="token punctuation">:</span> #248459<span class="token punctuation">;</span>\n  <span class="token property">--prism-function</span><span class="token punctuation">:</span> #849145<span class="token punctuation">;</span>\n  <span class="token property">--prism-deleted</span><span class="token punctuation">:</span> #a14f55<span class="token punctuation">;</span>\n  <span class="token property">--prism-class</span><span class="token punctuation">:</span> #2b91af<span class="token punctuation">;</span>\n  <span class="token property">--prism-builtin</span><span class="token punctuation">:</span> #a52727<span class="token punctuation">;</span>\n  <span class="token property">--prism-property</span><span class="token punctuation">:</span> #ad502b<span class="token punctuation">;</span>\n  <span class="token property">--prism-namespace</span><span class="token punctuation">:</span> #c96880<span class="token punctuation">;</span>\n  <span class="token property">--prism-punctuation</span><span class="token punctuation">:</span> #8e8f8b<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><p>To have it supports dark mode is extremely simple as well:</p><pre class="language-css"><code class="language-css"><span class="token selector">html:not(.dark)</span> <span class="token punctuation">{</span>\n  <span class="token property">--prism-foreground</span><span class="token punctuation">:</span> #393a34<span class="token punctuation">;</span>\n  <span class="token property">--prism-background</span><span class="token punctuation">:</span> #f8f8f8<span class="token punctuation">;</span>\n  <span class="token property">--prism-comment</span><span class="token punctuation">:</span> #758575<span class="token punctuation">;</span>\n  <span class="token property">--prism-namespace</span><span class="token punctuation">:</span> #444444<span class="token punctuation">;</span>\n  <span class="token property">--prism-string</span><span class="token punctuation">:</span> #bc8671<span class="token punctuation">;</span>\n  <span class="token property">--prism-punctuation</span><span class="token punctuation">:</span> #80817d<span class="token punctuation">;</span>\n  <span class="token property">--prism-literal</span><span class="token punctuation">:</span> #36acaa<span class="token punctuation">;</span>\n  <span class="token property">--prism-keyword</span><span class="token punctuation">:</span> #248459<span class="token punctuation">;</span>\n  <span class="token property">--prism-function</span><span class="token punctuation">:</span> #849145<span class="token punctuation">;</span>\n  <span class="token property">--prism-deleted</span><span class="token punctuation">:</span> #9a050f<span class="token punctuation">;</span>\n  <span class="token property">--prism-class</span><span class="token punctuation">:</span> #2b91af<span class="token punctuation">;</span>\n  <span class="token property">--prism-builtin</span><span class="token punctuation">:</span> #800000<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token selector">html.dark</span> <span class="token punctuation">{</span>\n  <span class="token property">--prism-foreground</span><span class="token punctuation">:</span> #d4d4d4<span class="token punctuation">;</span>\n  <span class="token property">--prism-background</span><span class="token punctuation">:</span> #1e1e1e<span class="token punctuation">;</span>\n  <span class="token property">--prism-namespace</span><span class="token punctuation">:</span> #aaaaaa<span class="token punctuation">;</span>\n  <span class="token property">--prism-comment</span><span class="token punctuation">:</span> #758575<span class="token punctuation">;</span>\n  <span class="token property">--prism-namespace</span><span class="token punctuation">:</span> #444444<span class="token punctuation">;</span>\n  <span class="token property">--prism-string</span><span class="token punctuation">:</span> #ce9178<span class="token punctuation">;</span>\n  <span class="token property">--prism-punctuation</span><span class="token punctuation">:</span> #d4d4d4<span class="token punctuation">;</span>\n  <span class="token property">--prism-literal</span><span class="token punctuation">:</span> #36acaa<span class="token punctuation">;</span>\n  <span class="token property">--prism-keyword</span><span class="token punctuation">:</span> #38a776<span class="token punctuation">;</span>\n  <span class="token property">--prism-function</span><span class="token punctuation">:</span> #dcdcaa<span class="token punctuation">;</span>\n  <span class="token property">--prism-deleted</span><span class="token punctuation">:</span> #9a050f<span class="token punctuation">;</span>\n  <span class="token property">--prism-class</span><span class="token punctuation">:</span> #4ec9b0<span class="token punctuation">;</span>\n  <span class="token property">--prism-builtin</span><span class="token punctuation">:</span> #d16969<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><p>That’s all. You can also play with the themes in the <a href="https://prism-theme-vars.netlify.app/">Playground</a> and make some your own within 5 mins. I created my first code theme in my life using it, which is also exactly what you are looking at :)</p><h3 id="serve-side-generatation-ssg"><a class="header-anchor" href="#serve-side-generatation-ssg" aria-hidden="true">#</a> Serve-Side Generatation (SSG)</h3><p>While Codecember is more like a site than an app, we would need to do some server-side generation to improve our <a href="https://searchengineland.com/guide/what-is-seo">SEO</a>. Read quite a lot of code from <a href="https://github.com/vuejs/vitepress">VitePress</a>, I came up with this plugin:</p><ul><li><a href="https://github.com/antfu/vite-ssg">vite-ssg</a> - Server-side generation for Vite.</li></ul><p>The idea here is fairly simple: bundle the app entry, then for each route, dump the app using APIs from the <a href="https://github.com/vuejs/vue-next/tree/master/packages/server-renderer"><code>@vue/server-renderer</code></a> package. Simplified code here:</p><pre class="language-ts"><code class="language-ts"><span class="token keyword">import</span> <span class="token punctuation">{</span> renderToString <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vue/server-renderer&#39;</span>\n\n<span class="token keyword">const</span> createApp <span class="token operator">=</span> <span class="token function">required</span><span class="token punctuation">(</span><span class="token string">&#39;dist-ssr/app.js&#39;</span><span class="token punctuation">)</span>\n\n<span class="token keyword">await</span> <span class="token builtin">Promise</span><span class="token punctuation">.</span><span class="token function">all</span><span class="token punctuation">(</span>\n  routes<span class="token punctuation">.</span><span class="token function">map</span><span class="token punctuation">(</span><span class="token keyword">async</span><span class="token punctuation">(</span>route<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    <span class="token keyword">const</span> <span class="token punctuation">{</span> app<span class="token punctuation">,</span> router<span class="token punctuation">,</span> head <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">createApp</span><span class="token punctuation">(</span><span class="token boolean">false</span><span class="token punctuation">)</span>\n\n    router<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>route<span class="token punctuation">)</span>\n    <span class="token keyword">await</span> router<span class="token punctuation">.</span><span class="token function">isReady</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n\n    <span class="token keyword">const</span> appHTML <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">renderToString</span><span class="token punctuation">(</span>app<span class="token punctuation">)</span>\n    <span class="token keyword">const</span> renderedHTML <span class="token operator">=</span> <span class="token function">renderHTML</span><span class="token punctuation">(</span>indexHTML<span class="token punctuation">,</span> appHTML<span class="token punctuation">)</span>\n\n    <span class="token keyword">await</span> fs<span class="token punctuation">.</span><span class="token function">writeFile</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">`</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">${</span>route<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">.html</span><span class="token template-punctuation string">`</span></span><span class="token punctuation">,</span> renderedHTML<span class="token punctuation">,</span> <span class="token string">&#39;utf-8&#39;</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span><span class="token punctuation">)</span>\n<span class="token punctuation">)</span>\n</code></pre><p>The full code can be found <a href="https://github.com/antfu/vite-ssg/blob/fa256449923e05e55bf15dcf4747d517bc22e33a/src/node/build.ts#L94-L104">here</a>.</p><p>With the <a href="https://github.com/vueuse/head">@vueuse/head</a> package made by <a href="https://github.com/egoist">@egoist</a>, I made the document head/meta manipulation in SSG with ease. Combining with <a href="https://github.com/antfu/vite-plugin-md">vite-plugin-md</a>, you can even use the frontmatter to set the meta (title, description, og:image, etc.).</p><pre class="language-html"><code class="language-html"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">setup</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n<span class="token keyword">import</span> <span class="token punctuation">{</span> useHead <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vueuse/head&#39;</span>\n\n<span class="token function">useHead</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  title<span class="token operator">:</span> <span class="token string">&#39;Website Title&#39;</span><span class="token punctuation">,</span>\n  meta<span class="token operator">:</span> <span class="token punctuation">[</span>\n    <span class="token punctuation">{</span>\n      name<span class="token operator">:</span> <span class="token string">&#39;description&#39;</span><span class="token punctuation">,</span>\n      content<span class="token operator">:</span> <span class="token string">&#39;Website description&#39;</span><span class="token punctuation">,</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token punctuation">]</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n</code></pre><h3 id="the-vite-template"><a class="header-anchor" href="#the-vite-template" aria-hidden="true">#</a> The Vite Template</h3><p>I found myself making small web apps frequently. Setting up plugins and configs for Vite kinda becomes the bottleneck for me to make my idea landded. So combining with those tools I am using, I made an opinionated template for myself but unexpectedly got quite some good feedback:</p><ul><li><a href="https://github.com/antfu/vitesse">Vitesse</a> - Opinionated Vite Starter Template</li></ul><h2 id="this-website"><a class="header-anchor" href="#this-website" aria-hidden="true">#</a> This Website</h2><p>This site is <strong>made from <a href="https://github.com/antfu/vitesse">Vitesse</a> combining with all the tools I mentioned above</strong>. To be honest, even making a static site generator right is something hard to me, not to mention that most of the hard parts are already handled by Vite. I am really happy to see so many things I have learned and crafted along the way. And glad I can make these contributions to the Vite ecosystem, that someone could find my work useful for building their apps.</p><h2 id="thanks"><a class="header-anchor" href="#thanks" aria-hidden="true">#</a> Thanks</h2><p>I can’t make all these happened without the help/support from the great community, thank y’all!</p><p>Also want to have some special thanks to people made significant contributions towards these projects 🙌 (A-Z)</p><ul><li><a href="https://github.com/hannoeru">@hannoeru</a></li><li><a href="https://github.com/matias-capeletto">@matias-capeletto</a></li><li><a href="https://github.com/privatenumber">@privatenumber</a></li><li><a href="https://github.com/sibbng">@sibbng</a></li></ul><p>Appreciation to my sponsors as well for supporting my works:</p><p align="center"><a href="https://cdn.jsdelivr.net/gh/antfu/static/sponsors.svg"><img src="https://cdn.jsdelivr.net/gh/antfu/static/sponsors.svg"></a></p><p>And thank you for reading through!</p><p><strong>This site is now open sourced at <a href="https://github.com/antfu/antfu.me">antfu/antfu.me</a></strong></p>',36),I={expose:[],setup(t){const e={title:"Rewrite in Vite",date:"2021-01-31T16:00:00.000Z",lang:"en",duration:"10min",description:"My site is now powered by Vite!",meta:[{property:"og:title",content:"Rewrite in Vite"},{property:"og:description",content:"My site is now powered by Vite!"},{name:"description",content:"My site is now powered by Vite!"}]};return i(e),(t,o)=>{const p=y,i=u;return n(),s(i,{frontmatter:e},{default:c((()=>[a("div",w,[b,a(p,{class:"text-xl pb-2 pt-1"}),v])])),_:1})}}};export default I;
